import{_ as e,o as a,c as n,ag as t}from"./chunks/framework.DXGyWiRo.js";const l="/images/lekt0301.jpg",r="/images/lekt0302.jpg",u="/images/lekt0303.jpg",f=JSON.parse('{"title":"Lektion 3","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion03.md","filePath":"lektionen/lektion03.md"}'),s={name:"lektionen/lektion03.md"};function o(d,i,h,m,p,g){return a(),n("div",null,[...i[0]||(i[0]=[t('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-3" tabindex="-1">Lektion 3 <a class="header-anchor" href="#lektion-3" aria-label="Permalink to &quot;Lektion 3&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>3.1. Nominativ singular = prathamā ekavacanam = प्रथमा एकवचनम् (Fortsetzung) <ul><li>3.1.1. Nominativ Singular auf -s (Fortsetzung)</li><li>3.1.2. Nominativ singular ohne Endung</li></ul></li><li>3.2. Bildung der Feminina zu Maskulina (Adjektive und Substantive)</li><li>3.3. Nominativ plural = prathamā bahuvacanam = प्रथमा बहुचनम्</li><li>3.4. Vokalsandhi</li><li>3.5. Satzsandhi von -ās</li><li>3.6. Wortliste</li><li>3.7. Übung</li></ul><h2 id="_3-1-nominativ-singular-prathama-ekavacanam-प्रथमा-एकवचनम्-fortsetzung" tabindex="-1">3.1. Nominativ singular = prathamā ekavacanam = प्रथमा एकवचनम् (Fortsetzung) <a class="header-anchor" href="#_3-1-nominativ-singular-prathama-ekavacanam-प्रथमा-एकवचनम्-fortsetzung" aria-label="Permalink to &quot;3.1. Nominativ singular = prathamā ekavacanam = प्रथमा एकवचनम् (Fortsetzung)&quot;">​</a></h2><h3 id="_3-1-1-nominativ-singular-auf-s-fortsetzung" tabindex="-1">3.1.1. Nominativ Singular auf -s (Fortsetzung) <a class="header-anchor" href="#_3-1-1-nominativ-singular-auf-s-fortsetzung" aria-label="Permalink to &quot;3.1.1. Nominativ Singular auf -s (Fortsetzung)&quot;">​</a></h3><p>Auch folgende Nominalstämme, die mit einem Vokal enden, bilden den Nominativ Singular auf -s</p><ul><li>Feminina auf -i: z.B. śruti f. &quot;das Hören&quot; -- Nom. sg.: śrutis = श्रुतिस्</li><li>Feminina auf -u: z.B. dhenu f. &quot;Milchkuh&quot; -- Nom. sg.: dhenus = धेनुस्</li></ul><h3 id="_3-1-2-nominativ-singular-ohne-endung" tabindex="-1">3.1.2. Nominativ singular ohne Endung <a class="header-anchor" href="#_3-1-2-nominativ-singular-ohne-endung" aria-label="Permalink to &quot;3.1.2. Nominativ singular ohne Endung&quot;">​</a></h3><p>Den Nominativ singular bilden ohne Endung:</p><ul><li>Feminina auf -ā: z.B. devatā f. &quot;Gottheit&quot; -- Nom. sg.: devatā = देवता</li><li>Feminina auf -ī: z.B. devī f. &quot;Göttin&quot; -- Nom. sg.: devī = देवी</li></ul><p>Achtung!! daneben gibt es einsilbige feminine Wurzelnomina auf -ī, deren Nominativ singular auf -s endet: z.B. dhī f. &quot;Gedanke&quot; -- Nom. sg.: dhīs = धीस् ; auch  lakṣmī लक्ष्मी f. &quot;Lakṣmī&quot; (sowie tarī = तरी f. &quot;Boot&quot; und tantrī = तन्त्री f. &quot;Saite&quot;) bilden unregelmäßig den Nominativ singular auf -s: lakṣmīs = लक्ष्मीस्.</p><h2 id="_3-2-bildung-der-feminina-zu-maskulina-adjektive-und-substantive" tabindex="-1">3.2. Bildung der Feminina zu Maskulina (Adjektive und Substantive) <a class="header-anchor" href="#_3-2-bildung-der-feminina-zu-maskulina-adjektive-und-substantive" aria-label="Permalink to &quot;3.2. Bildung der Feminina zu Maskulina (Adjektive und Substantive)&quot;">​</a></h2><p>| Maskulina auf -a:</p><ul><li>Femininum auf -ā: z.B. kṣatriya m. » kṣatriyā f. &quot;Kṣatriyafrau&quot; = क्षत्रिया</li><li>Femininum auf -ī: z.B. brāhmaṇa m. » brāhmaṇī f. &quot;Brahmanin&quot; = ब्राह्मणी</li></ul><p>Eine feste Regel für die Verteilung der Feminina auf -ā bzw. -ī lässt sich nicht aufstellen, obwohl die indischen Grammatiker eine Anzahl von Regeln geben: s. z.B. M. R. Kale: A higher Sanskrit grammar. -- Delhi, 1969. -- § 305 - 336.</p><p>| | --- | | Maskulina auf -u:</p><ul><li>Femininum auf -ī: z.B. sādhu m. » sādhvī f. (gut, Heilige) = साध्वी</li></ul><p>-u- wird vor Vokal durch den ihm entsprechenden Halbvokal -v- ersetzt, darum -u-ī » -vī</p><p>|</p><h2 id="_3-3-nominativ-plural-prathama-bahuvacanam-प्रथमा-बहुचनम्" tabindex="-1">3.3. Nominativ plural = prathamā bahuvacanam = प्रथमा बहुचनम् <a class="header-anchor" href="#_3-3-nominativ-plural-prathama-bahuvacanam-प्रथमा-बहुचनम्" aria-label="Permalink to &quot;3.3. Nominativ plural = prathamā bahuvacanam = प्रथमा बहुचनम्&quot;">​</a></h2><p>Die Endung des Nominativ plural (prathamā bahuvacanam) im Maskulinum und Femininum ist -as.</p><ul><li>Maskulina auf -a: deva- + -as » devās = देवास्</li><li>Feminina auf -ā: devatā- + -as » devatās = देवतास्</li><li>Maskulina auf -i: kavi-  » Hochstufe: kave- + -as  » kavayas = कवयस्</li><li>Feminina auf -i: śruti-  » Hochstufe: śrute- + -as  » śrutayas =  श्रुतयस्</li><li>Feminin auf -ī: devī- + -as  » devyas = देव्यस्</li><li>Maskulina auf -u: guru-  » Hochstufe: guro- + as  » guravas = गुरवस्</li><li>Feminina auf -u: dhenu-  » Hochstufe: dheno- + -as  » dhenavas = धेनवस्</li></ul><p>Anmerkung: e ist Hochstufe (guṇa) zu i, o ist Hochstufe zu u; ay ist der Vertreter von e vor Vokalen, av ist der Vertreter von o vor Vokalen; y ist der halbvokalische Vertreter von i bzw. ī vor Vokalen.</p><h2 id="_3-4-vokalsandhi" tabindex="-1">3.4. Vokalsandhi <a class="header-anchor" href="#_3-4-vokalsandhi" aria-label="Permalink to &quot;3.4. Vokalsandhi&quot;">​</a></h2><p>Einfache Vokale, die sich nicht oder nur in ihrer Länge unterscheiden, &quot;verschmelzen&quot; zum entsprechenden langen Vokal:</p><ul><li>-a / -ā + a- / ā- » -ā-</li><li>-i /-ī + i- / ī- » -ī-</li><li>-u / -ū + u- / ū-  » -ū-</li><li>(-ṛ + ṛ-  » -ṝ-)</li></ul><p>z.B.</p><p>devatā + annapūrṇā » devatānnapūrṇā &quot;Annapūrṇā ist eine Gottheit&quot; = देवतान्नपूर्णा</p><blockquote><p>(Annapūrṇā ist die Göttin der Speisen und des Kochens, sie gilt als eine Verkörperung Pārvatī&#39;s, der Gattin Śivas.)</p></blockquote><p>devī + indrāṇī » devīndrāṇī &quot;Indrāṇī ist eine Göttin&quot; = देवीन्द्राणी</p><blockquote><p>(Indrāṇī ist die Gattin des Gottes Indra.)</p></blockquote><p><img src="'+l+'" alt=""><br> Abb.: Indra und Indrāṇī auf dem Elefanten Airavata, Miniatur, Rājasthān, 1670/80<br> [Bildquelle. Wikipedia, Public domain]</p><p>Einfache Vokale -- außer -a / -ā -- werden vor unähnlichen Vokalen durch den ihnen entsprechenden halbvokal ersetzt:</p><ul><li>-i / -ī vor a- / ā- / u- / ū-  ... / au » -y</li><li>-u / -ū vor a- / ā- / i- / ī- / ṛ-  ... / au » -v</li><li>-ṛ vor a- / ā- / i- / ī- / u- / ū-  ... / au » -r</li></ul><p>(!! Zu dieser Regel gibt es insbesondere für Dualformen Ausnahmen !!)</p><p>z.B.</p><p>devī + umā » devy umā &quot;Umā ist eine / die Göttin&quot; = देव्युमा</p><blockquote><p>(Umā ist ein Name für Pārvatī, die Gattin Śivas)</p></blockquote><p>-a / -ā vor unähnlichem Vokal:</p><ul><li>-a / -ā + i- / ī » -e-</li><li>-a / -ā + ṛ- » -ar-</li><li>-a / -ā + e- / ai- » -ai-</li><li>-a / -ā + o- / au- » -au-</li></ul><p>Für diesen Sandhi gilt also folgendes Schema:</p><p><img src="'+r+'" alt=""></p><p>Zu dieser sog. Stammabstufung siehe später!</p><p>z.B.</p><p>śūdrā + itarā » śudretarā &quot;Itarā ist eine Śūdrafrau&quot; = शूद्रेतरा</p><h2 id="_3-5-satzsandhi-von-as" tabindex="-1">3.5. Satzsandhi von -ās <a class="header-anchor" href="#_3-5-satzsandhi-von-as" aria-label="Permalink to &quot;3.5. Satzsandhi von -ās&quot;">​</a></h2><p>-ās wird vor allen stimmhaften Lauten durch -ā ersetzt.</p><p>z.B.</p><p>dvijās + vaiśyāḥ » dvijā vaiśyāh &quot;Vaiśyas sind Zweimalgeborene&quot; = द्विजा वैश्याः</p><h2 id="_3-6-wortliste" tabindex="-1">3.6. Wortliste <a class="header-anchor" href="#_3-6-wortliste" aria-label="Permalink to &quot;3.6. Wortliste&quot;">​</a></h2><p>Lernen Sie folgende Wörter:</p><p>śruti f. = श्रुति:  das Hören, die ewige Überlieferung (Bezeichnung für die Veden und Brāhmaṇa&#39;s)</p><p>smṛti f. = स्मृति: Vergegenwärtigung, Erinnerung, meditative Vergegenwärtigung = Achtsamkeit, Überlieferung (Gegenbegriff zu śruti. Umfasst:</p><ul><li>die sechs vedāṅga n. = वेदाङ्ग <ol><li>śikṣā f. = शिक्षा: rechte Aussprache</li><li>chandas n. = छन्दस्  Metrum</li><li>vyākaraṇa n. = व्याकरण: Grammatik</li><li>nirukta n. = निरुक्त : Worterklärung, Etymologie</li><li>jyotiṣa n. =ज्योतिष : Astronomie, Kalenderlehre</li><li>kalpa m. = कल्प : Zeremoniell</li></ol></li><li>śrautasūtra n. = श्रौतसूत्र : Lehrwerke für den Vollzug der großen Opfer</li><li>gṛhyasūtra n. = गृह्यसूत्र : Lehrwerke für die Zeremonien und Opfer des täglichen Lebens</li><li>dharmasūtra n. = धर्मसूत्र und dharmaśāstra n. = धर्मशास्त्र : Lehrwerke zu Recht und Sitte (rechtes Verhalten)</li><li>die großen Epen mahābhārata n. = महाभारत und rāmāyaṇa n. = रामायण</li><li>die purāṇa n. = पुराण</li><li>nītiśāstra n = नीतिशास्त्र : Lehrwerke der Lebensklugheit</li></ul><p>smṛti ist besonders auch Bezeichnung für Dharmalehrwerke</p><p>dhenu f. = धेनु : (Milch-)kuh</p><p>paśu m. =पशु : domestiziertes Nutztier, Vieh (Kollektivum)</p><p>devatā f. = देवता : Gottheit (abstrakt und konkret)</p><p>brāhmaṇī f. = ब्राह्मणी : Brahmanin</p><p>kṣatriyā f. = क्षत्रिया : weibliche Kṣatriya</p><p>kṣatriyī f. = क्षत्रियी : Frau eines Kṣatriya</p><p>vaiṣyā f. = वैश्या : weibliche Vaiśya</p><p>śūdrā f. = शूद्रा : weibliche Śūdra</p><p>śūdrī f. / śūdrāṇī f. = शूद्री शूद्राणी : Frau eines Śūdra</p><p>devī f. = देवी : Göttin, insbes. Durgā f. = दुर्गा, die Gattin Śiva&#39;s = शिव</p><p><img src="'+u+'" alt=""><br> Abb.: Durgā = दुर्गा, Orissa (ଓଡ଼ିଶା)<br> [Bildquelle: Wikipedia, GNU FDLizenz]</p><p>sādhvī f. = साध्वी : fem. zu sādhu</p><p>gurvī f. = गुर्वी : fem. zu guru</p><p>asmitā f. = अस्मिता : &quot;Ich-bin-heit&quot;, d.h. der (falsche) Glaube: Ich bin es, der sieht usw.</p><p>ānvīkṣikī f. = आन्वीक्षिकी : Philosophie (die Wissenschaft, die durch logisch korrekte Begründungen zu ihren Schlussfolgerungen kommt)</p><p>upekṣā f. = उपेक्षा : Nichtbeachtung, Gleichmut</p><p>karuṇā f. = करुणा : Mitgefühl, Mitleid</p><p>muditā f. = मुदिता : Freude, insbesondere Mitfreude (Gegensatz zu Neid)</p><h2 id="_3-7-ubung" tabindex="-1">3.7. Übung <a class="header-anchor" href="#_3-7-ubung" aria-label="Permalink to &quot;3.7. Übung&quot;">​</a></h2><p>A) Setzen Sie folgende Sätze in den Plural:</p><ol><li>dvijo brāhmaṇaḥ = द्विजो ब्राह्मणः</li><li>dvijaḥ kṣatriyaḥ = द्विजः क्षत्रियः</li><li>dvijo vaiśyaḥ = द्विजो वैश्यः</li><li>gurur brāhmaṇaḥ = गुरुर्ब्राह्मणः</li><li>sādhur guruḥ = साधुर्गुरुः</li><li>guruḥ kaviḥ = गुरुः कविः</li><li>sādhvī brāhmaṇī = साध्वी ब्राह्मणी</li><li>devatā guruḥ = देवता गुरुः</li><li>paśur dhenuḥ = पशुर्धेनुः</li><li>gurvī sādhvī = गुर्वी साध्वी</li></ol><p>B) Bilden Sie durch Einsetzen Nominalsätze:</p><ol><li>śrutis ... (veda) = श्रुतिस् ... वेद</li><li>paśus ... (dhenu) = पशुस् ... धेनु</li><li>devī ... (durgā, umā, indrāṇī) = देवी ... दुर्गा, उमा, इन्द्राणी</li><li>devatā ... (mīnākṣī, annapūrṇā) = देवता ... मीनाक्षी, अन्नपूर्णा</li><li>śūdrā ... (itarā) = शूद्रा ... इतरा</li></ol><p>C) Übertragen Sie ins Femininum:</p><ol><li>gurur brāhmaṇaḥ = गुरुर्ब्राह्मणः</li><li>sādhur guruḥ = साधुर्गुरुः</li><li>kṣatriyaḥ sādhuḥ = क्षत्रियः साधुः</li></ol><p>D) Übersetzen Sie ins Sanskrit:</p><ol><li>Umā ist eine Göttin.</li><li>Der Veda ist śruti.</li><li>Die Lehrerinnen sind Göttinnen.</li><li>Milchkühe sind domestizierte Tiere.</li><li>Dichter sind Lehrer.</li><li>Kṣatriyas sind Zweimalgeborene.</li><li>Die heiligen Männer sind Śūdras.</li></ol>',83)])])}const c=e(s,[["render",o]]);export{f as __pageData,c as default};
